(function(){var sliders=document.querySelectorAll("[data-hero-slider]");if(!sliders.length){return}sliders.forEach(function(slider){var slides=slider.querySelectorAll("[data-hero-slide]");var prev=slider.querySelector("[data-hero-prev]");var next=slider.querySelector("[data-hero-next]");var index=0;var timer=null;if(slides.length<2){return}var show=function(newIndex){slides[index].classList.remove("is-active");index=(newIndex+slides.length)%slides.length;slides[index].classList.add("is-active")};var start=function(){timer=window.setInterval(function(){show(index+1)},5000)};var restart=function(){if(timer){window.clearInterval(timer)}start()};prev&&prev.addEventListener("click",function(){show(index-1);restart()});next&&next.addEventListener("click",function(){show(index+1);restart()});start()})})();
(function(){var wrap=document.querySelector("[data-mobile-slider]");if(!wrap)return;var slides=wrap.querySelectorAll("[data-mobile-slide]");var prev=wrap.querySelector("[data-mobile-prev]");var next=wrap.querySelector("[data-mobile-next]");var dots=wrap.querySelectorAll("[data-mobile-dot]");var idx=0;var timer=null;if(!slides.length)return;var show=function(n){slides[idx].classList.remove("is-active");if(dots[idx])dots[idx].classList.remove("is-active");idx=(n+slides.length)%slides.length;slides[idx].classList.add("is-active");if(dots[idx])dots[idx].classList.add("is-active")};var restart=function(){if(timer)clearInterval(timer);if(slides.length>1)timer=setInterval(function(){show(idx+1)},4500)};prev&&prev.addEventListener("click",function(){show(idx-1);restart()});next&&next.addEventListener("click",function(){show(idx+1);restart()});dots.forEach(function(dot){dot.addEventListener("click",function(){show(parseInt(dot.getAttribute("data-mobile-dot"),10));restart()})});restart()})();